+// =========================================================================
+// 3. Computed Values
+// =========================================================================
+
+mod bind_computed {
+    use super::*;
+
+    #[test]
+    fn single_dependency_computed() {
+        let count = Observable::new(5);
+        let doubled = Computed::from_observable(&count, |v| v * 2);
+
+        assert_eq!(doubled.get(), 10);
+        count.set(7);
+        assert_eq!(doubled.get(), 14);
+    }
+
+    #[test]
+    fn multi_dependency_computed() {
